// optional import of sdk modules
import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {
  const configGet = await fetch(`/platform/automation/v1/executions/${execution_id}/tasks/search-for-existing-issue/result`);
  const configBody = await configGet.json();
  console.log(configBody.length)

  if (configBody.length == 0) {

        throw new Error("No record found yet, failing on purpose for restart!");
  } 

  return configBody;
}
